CREATE PROCEDURE `sp_reclaim_locations`()
BEGIN

  UPDATE inventory

  SET    location_text = '',

         status        = 'zero'

  WHERE  quantity    = 0

    AND  zero_since IS NOT NULL

    AND  TIMESTAMPDIFF(DAY, zero_since, NOW()) >= 3;

END ;;
